package com.oneil.wellness.walkplanner.calendar.provider.google;
import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;import java.net.URI;import java.time.OffsetDateTime;import java.util.*;import org.junit.jupiter.api.Test;
class GoogleCalendarClientTest {
 private GoogleCalendarConfiguration config(){var c=new GoogleCalendarConfiguration();c.setApiBaseUrl(URI.create("https://example.test/calendar/v3"));c.setMaximumEventsPerCalendar(10);return c;}
 @Test void followsCalendarAndEventPagination(){var http=new QueueTransport(new GoogleHttpTransport.Response(200,"{\"items\":[{\"id\":\"one\"}],\"nextPageToken\":\"next\"}"),new GoogleHttpTransport.Response(200,"{\"items\":[{\"id\":\"two\"}]}"),new GoogleHttpTransport.Response(200,"{\"items\":[{\"id\":\"event1\"}],\"nextPageToken\":\"next\"}"),new GoogleHttpTransport.Response(200,"{\"items\":[{\"id\":\"event2\"}]}"));var tokens=mock(GoogleTokenService.class);when(tokens.accessToken()).thenReturn("secret");var client=new GoogleCalendarClient(config(),http,tokens);assertEquals(2,client.listCalendars().size());assertEquals(2,client.listEvents("one",OffsetDateTime.parse("2026-07-20T00:00:00Z"),OffsetDateTime.parse("2026-07-21T00:00:00Z")).size());assertFalse(http.requests.stream().anyMatch(s->s.contains("secret")));}
 @Test void mapsAuthorizationAndRateLimitFailures(){var tokens=mock(GoogleTokenService.class);when(tokens.accessToken()).thenReturn("token");var unauthorized=new GoogleCalendarClient(config(),new QueueTransport(new GoogleHttpTransport.Response(401,"{}")),tokens);assertTrue(assertThrows(GoogleProviderException.class,unauthorized::listCalendars).isAuthorizationRequired());var limited=new GoogleCalendarClient(config(),new QueueTransport(new GoogleHttpTransport.Response(429,"{}"),new GoogleHttpTransport.Response(500,"{}"),new GoogleHttpTransport.Response(503,"{}")),tokens);assertEquals("RATE_LIMITED",assertThrows(GoogleProviderException.class,limited::listCalendars).getCode());}
 static class QueueTransport implements GoogleHttpTransport{Deque<Response> responses;List<String> requests=new ArrayList<>();QueueTransport(Response...r){responses=new ArrayDeque<>(List.of(r));}public Response exchange(String m,URI u,Map<String,String> h,String b){requests.add(m+" "+u);return responses.removeFirst();}}
}
